128	static ngx_int_t
129	ngx_http_upstream_init_hash_peer(ngx_http_request_t *r,
130	    ngx_http_upstream_srv_conf_t *us)
131	{
132	    ngx_http_upstream_hash_srv_conf_t   *hcf;
133	    ngx_http_upstream_hash_peer_data_t  *hp;
134	
135	    hp = ngx_palloc(r->pool, sizeof(ngx_http_upstream_hash_peer_data_t));
136	    if (hp == NULL) {
137	        return NGX_ERROR;
138	    }
139	
140	    r->upstream->peer.data = &hp->rrp;
141	
142	    if (ngx_http_upstream_init_round_robin_peer(r, us) != NGX_OK) {
143	        return NGX_ERROR;
144	    }
145	
146	    r->upstream->peer.get = ngx_http_upstream_get_hash_peer;
147	
148	    hcf = ngx_http_conf_upstream_srv_conf(us, ngx_http_upstream_hash_module);
149	
150	    if (ngx_http_complex_value(r, &hcf->key, &hp->key) != NGX_OK) {
151	        return NGX_ERROR;
152	    }
153	
154	    ngx_log_debug1(NGX_LOG_DEBUG_HTTP, r->connection->log, 0,
155	                   "upstream hash key:\"%V\"", &hp->key);
156	
157	    hp->conf = hcf;
158	    hp->tries = 0;
159	    hp->rehash = 0;
160	    hp->hash = 0;
161	    hp->get_rr_peer = ngx_http_upstream_get_round_robin_peer;
162	
163	    return NGX_OK;
164	}
