167	static ngx_int_t
168	ngx_http_upstream_get_hash_peer(ngx_peer_connection_t *pc, void *data)
169	{
170	    ngx_http_upstream_hash_peer_data_t  *hp = data;
171	
172	    time_t                        now;
173	    u_char                        buf[NGX_INT_T_LEN];
174	    size_t                        size;
175	    uint32_t                      hash;
176	    ngx_int_t                     w;
177	    uintptr_t                     m;
178	    ngx_uint_t                    n, p;
179	    ngx_http_upstream_rr_peer_t  *peer;
180	
181	    ngx_log_debug1(NGX_LOG_DEBUG_HTTP, pc->log, 0,
182	                   "get hash peer, try: %ui", pc->tries);
183	
184	    ngx_http_upstream_rr_peers_rlock(hp->rrp.peers);
185	
186	    if (hp->tries > 20 || hp->rrp.peers->number < 2 || hp->key.len == 0) {
187	        ngx_http_upstream_rr_peers_unlock(hp->rrp.peers);
188	        return hp->get_rr_peer(pc, &hp->rrp);
189	    }
190	
191	#if (NGX_HTTP_UPSTREAM_ZONE)
192	    if (hp->rrp.peers->config && hp->rrp.config != *hp->rrp.peers->config) {
193	        ngx_http_upstream_rr_peers_unlock(hp->rrp.peers);
194	        return hp->get_rr_peer(pc, &hp->rrp);
195	    }
196	#endif
197	
198	    now = ngx_time();
199	
200	    pc->cached = 0;
201	    pc->connection = NULL;
202	
203	#if (NGX_HTTP_UPSTREAM_SID)
204	    peer = ngx_http_upstream_get_rr_peer_by_sid(&hp->rrp, pc->hint, &p, 1);
205	
206	    if (peer) {
207	        n = p / (8 * sizeof(uintptr_t));
208	        m = (uintptr_t) 1 << p % (8 * sizeof(uintptr_t));
209	
210	        goto found;
211	    }
212	#endif
213	
214	    for ( ;; ) {
215	
216	        /*
217	         * Hash expression is compatible with Cache::Memcached:
218	         * ((crc32([REHASH] KEY) >> 16) & 0x7fff) + PREV_HASH
219	         * with REHASH omitted at the first iteration.
220	         */
221	
222	        ngx_crc32_init(hash);
223	
224	        if (hp->rehash > 0) {
225	            size = ngx_sprintf(buf, "%ui", hp->rehash) - buf;
226	            ngx_crc32_update(&hash, buf, size);
227	        }
228	
229	        ngx_crc32_update(&hash, hp->key.data, hp->key.len);
230	        ngx_crc32_final(hash);
231	
232	        hash = (hash >> 16) & 0x7fff;
233	
234	        hp->hash += hash;
235	        hp->rehash++;
236	
237	        w = hp->hash % hp->rrp.peers->total_weight;
238	        peer = hp->rrp.peers->peer;
239	        p = 0;
240	
241	        while (w >= peer->weight) {
242	            w -= peer->weight;
243	            peer = peer->next;
244	            p++;
245	        }
246	
247	        n = p / (8 * sizeof(uintptr_t));
248	        m = (uintptr_t) 1 << p % (8 * sizeof(uintptr_t));
249	
250	        if (hp->rrp.tried[n] & m) {
251	            goto next;
252	        }
253	
254	        ngx_http_upstream_rr_peer_lock(hp->rrp.peers, peer);
255	
256	        ngx_log_debug2(NGX_LOG_DEBUG_HTTP, pc->log, 0,
257	                       "get hash peer, value:%uD, peer:%ui", hp->hash, p);
258	
259	        if (peer->down) {
260	            ngx_http_upstream_rr_peer_unlock(hp->rrp.peers, peer);
261	            goto next;
262	        }
263	
264	        if (peer->max_fails
265	            && peer->fails >= peer->max_fails
266	            && now - peer->checked <= peer->fail_timeout)
267	        {
268	            ngx_http_upstream_rr_peer_unlock(hp->rrp.peers, peer);
269	            goto next;
270	        }
271	
272	        if (peer->max_conns && peer->conns >= peer->max_conns) {
273	            ngx_http_upstream_rr_peer_unlock(hp->rrp.peers, peer);
274	            goto next;
275	        }
276	
277	        break;
278	
279	    next:
280	
281	        if (++hp->tries > 20) {
282	            ngx_http_upstream_rr_peers_unlock(hp->rrp.peers);
283	            return hp->get_rr_peer(pc, &hp->rrp);
284	        }
285	    }
286	
287	#if (NGX_HTTP_UPSTREAM_SID)
288	found:
289	#endif
290	
291	    hp->rrp.current = peer;
292	    ngx_http_upstream_rr_peer_ref(hp->rrp.peers, peer);
293	
294	    pc->sockaddr = peer->sockaddr;
295	    pc->socklen = peer->socklen;
296	    pc->name = &peer->name;
297	
298	#if (NGX_HTTP_UPSTREAM_SID)
299	    pc->sid = &peer->sid;
300	#endif
301	
302	    peer->conns++;
303	
304	    if (now - peer->checked > peer->fail_timeout) {
305	        peer->checked = now;
306	    }
307	
308	    ngx_http_upstream_rr_peer_unlock(hp->rrp.peers, peer);
309	    ngx_http_upstream_rr_peers_unlock(hp->rrp.peers);
310	
311	    hp->rrp.tried[n] |= m;
312	
313	    return NGX_OK;
314	}
