318	ngx_http_upstream_init_chash(ngx_conf_t *cf, ngx_http_upstream_srv_conf_t *us)
319	{
320	    if (ngx_http_upstream_init_round_robin(cf, us) != NGX_OK) {
321	        return NGX_ERROR;
322	    }
323	
324	    us->peer.init = ngx_http_upstream_init_chash_peer;
325	
326	#if (NGX_HTTP_UPSTREAM_ZONE)
327	    if (us->shm_zone) {
