335	
336	static ngx_int_t
337	ngx_http_upstream_update_chash(ngx_pool_t *pool,
338	    ngx_http_upstream_srv_conf_t *us)
339	{
340	    u_char                             *host, *port, c;
341	    size_t                              host_len, port_len, size;
342	    uint32_t                            hash, base_hash;
343	    ngx_str_t                          *server;
344	    ngx_uint_t                          npoints, i, j;
345	    ngx_http_upstream_rr_peer_t        *peer;
346	    ngx_http_upstream_rr_peers_t       *peers;
347	    ngx_http_upstream_chash_points_t   *points;
348	    ngx_http_upstream_hash_srv_conf_t  *hcf;
349	    union {
350	        uint32_t                        value;
351	        u_char                          byte[4];
352	    } prev_hash;
353	
354	    hcf = ngx_http_conf_upstream_srv_conf(us, ngx_http_upstream_hash_module);
355	
356	    if (hcf->points) {
357	        ngx_free(hcf->points);
358	        hcf->points = NULL;
359	    }
360	
361	    peers = us->peer.data;
362	    npoints = peers->total_weight * 160;
363	
364	    size = sizeof(ngx_http_upstream_chash_points_t)
365	           - sizeof(ngx_http_upstream_chash_point_t)
366	           + sizeof(ngx_http_upstream_chash_point_t) * npoints;
367	
368	    points = pool ? ngx_palloc(pool, size) : ngx_alloc(size, ngx_cycle->log);
369	    if (points == NULL) {
370	        return NGX_ERROR;
371	    }
372	
373	    points->number = 0;
374	
375	    if (npoints == 0) {
376	        hcf->points = points;
377	        return NGX_OK;
378	    }
379	
380	    for (peer = peers->peer; peer; peer = peer->next) {
381	        server = &peer->server;
382	
383	        /*
384	         * Hash expression is compatible with Cache::Memcached::Fast:
385	         * crc32(HOST \0 PORT PREV_HASH).
386	         */
387	
388	        if (server->len >= 5
389	            && ngx_strncasecmp(server->data, (u_char *) "unix:", 5) == 0)
390	        {
391	            host = server->data + 5;
392	            host_len = server->len - 5;
393	            port = NULL;
394	            port_len = 0;
395	            goto done;
396	        }
397	
398	        for (j = 0; j < server->len; j++) {
399	            c = server->data[server->len - j - 1];
400	
401	            if (c == ':') {
402	                host = server->data;
403	                host_len = server->len - j - 1;
404	                port = server->data + server->len - j;
405	                port_len = j;
406	                goto done;
407	            }
408	
409	            if (c < '0' || c > '9') {
410	                break;
411	            }
412	        }
413	
414	        host = server->data;
415	        host_len = server->len;
416	        port = NULL;
417	        port_len = 0;
418	
419	    done:
420	
421	        ngx_crc32_init(base_hash);
422	        ngx_crc32_update(&base_hash, host, host_len);
423	        ngx_crc32_update(&base_hash, (u_char *) "", 1);
424	        ngx_crc32_update(&base_hash, port, port_len);
425	
426	        prev_hash.value = 0;
427	        npoints = peer->weight * 160;
428	
429	        for (j = 0; j < npoints; j++) {
430	            hash = base_hash;
431	
432	            ngx_crc32_update(&hash, prev_hash.byte, 4);
433	            ngx_crc32_final(hash);
434	
435	            points->point[points->number].hash = hash;
436	            points->point[points->number].server = server;
437	            points->number++;
438	
439	#if (NGX_HAVE_LITTLE_ENDIAN)
440	            prev_hash.value = hash;
441	#else
442	            prev_hash.byte[0] = (u_char) (hash & 0xff);
443	            prev_hash.byte[1] = (u_char) ((hash >> 8) & 0xff);
444	            prev_hash.byte[2] = (u_char) ((hash >> 16) & 0xff);
445	            prev_hash.byte[3] = (u_char) ((hash >> 24) & 0xff);
446	#endif
447	        }
448	    }
449	
450	    ngx_qsort(points->point,
451	              points->number,
452	              sizeof(ngx_http_upstream_chash_point_t),
453	              ngx_http_upstream_chash_cmp_points);
454	
455	    for (i = 0, j = 1; j < points->number; j++) {
456	        if (points->point[i].hash != points->point[j].hash) {
457	            points->point[++i] = points->point[j];
458	        }
459	    }
460	
461	    points->number = i + 1;
462	
463	    hcf->points = points;
464	
465	    return NGX_OK;
466	}
