469	static int ngx_libc_cdecl
470	ngx_http_upstream_chash_cmp_points(const void *one, const void *two)
471	{
472	    ngx_http_upstream_chash_point_t *first =
473	                                       (ngx_http_upstream_chash_point_t *) one;
474	    ngx_http_upstream_chash_point_t *second =
475	                                       (ngx_http_upstream_chash_point_t *) two;
476	
477	    if (first->hash < second->hash) {
478	        return -1;
479	
480	    } else if (first->hash > second->hash) {
481	        return 1;
482	
483	    } else {
484	        return 0;
485	    }
486	}
