489	static ngx_uint_t
490	ngx_http_upstream_find_chash_point(ngx_http_upstream_chash_points_t *points,
491	    uint32_t hash)
492	{
493	    ngx_uint_t                        i, j, k;
494	    ngx_http_upstream_chash_point_t  *point;
495	
496	    /* find first point >= hash */
497	
498	    point = &points->point[0];
499	
500	    i = 0;
501	    j = points->number;
502	
503	    while (i < j) {
504	        k = (i + j) / 2;
505	
506	        if (hash > point[k].hash) {
507	            i = k + 1;
508	
509	        } else if (hash < point[k].hash) {
510	            j = k;
511	
512	        } else {
513	            return k;
514	        }
515	    }
516	
517	    return i;
518	}
