521	static ngx_int_t
522	ngx_http_upstream_init_chash_peer(ngx_http_request_t *r,
523	    ngx_http_upstream_srv_conf_t *us)
524	{
525	    uint32_t                             hash;
526	    ngx_http_upstream_hash_srv_conf_t   *hcf;
527	    ngx_http_upstream_hash_peer_data_t  *hp;
528	
529	    if (ngx_http_upstream_init_hash_peer(r, us) != NGX_OK) {
530	        return NGX_ERROR;
531	    }
532	
533	    r->upstream->peer.get = ngx_http_upstream_get_chash_peer;
534	
535	    hp = r->upstream->peer.data;
536	    hcf = ngx_http_conf_upstream_srv_conf(us, ngx_http_upstream_hash_module);
537	
538	    hash = ngx_crc32_long(hp->key.data, hp->key.len);
539	
540	    ngx_http_upstream_rr_peers_rlock(hp->rrp.peers);
541	
542	#if (NGX_HTTP_UPSTREAM_ZONE)
543	    if (hp->rrp.peers->config
544	        && (hcf->points == NULL || hcf->config != *hp->rrp.peers->config))
545	    {
546	        if (ngx_http_upstream_update_chash(NULL, us) != NGX_OK) {
547	            ngx_http_upstream_rr_peers_unlock(hp->rrp.peers);
548	            return NGX_ERROR;
549	        }
550	
551	        hcf->config = *hp->rrp.peers->config;
552	    }
553	#endif
554	
555	    if (hcf->points->number) {
556	        hp->hash = ngx_http_upstream_find_chash_point(hcf->points, hash);
557	    }
558	
559	    ngx_http_upstream_rr_peers_unlock(hp->rrp.peers);
560	
561	    return NGX_OK;
562	}
