565	static ngx_int_t
566	ngx_http_upstream_get_chash_peer(ngx_peer_connection_t *pc, void *data)
567	{
568	    ngx_http_upstream_hash_peer_data_t  *hp = data;
569	
570	    time_t                              now;
571	    intptr_t                            m;
572	    ngx_str_t                          *server;
573	    ngx_int_t                           total;
574	    ngx_uint_t                          i, n, best_i;
575	    ngx_http_upstream_rr_peer_t        *peer, *best;
576	    ngx_http_upstream_chash_point_t    *point;
577	    ngx_http_upstream_chash_points_t   *points;
578	    ngx_http_upstream_hash_srv_conf_t  *hcf;
579	
580	    ngx_log_debug1(NGX_LOG_DEBUG_HTTP, pc->log, 0,
581	                   "get consistent hash peer, try: %ui", pc->tries);
582	
583	    ngx_http_upstream_rr_peers_wlock(hp->rrp.peers);
584	
585	    if (hp->tries > 20 || hp->rrp.peers->single || hp->key.len == 0) {
586	        ngx_http_upstream_rr_peers_unlock(hp->rrp.peers);
587	        return hp->get_rr_peer(pc, &hp->rrp);
588	    }
589	
590	    pc->cached = 0;
591	    pc->connection = NULL;
592	
593	    if (hp->rrp.peers->number == 0) {
594	        pc->name = hp->rrp.peers->name;
595	        ngx_http_upstream_rr_peers_unlock(hp->rrp.peers);
596	        return NGX_BUSY;
597	    }
598	
599	#if (NGX_HTTP_UPSTREAM_ZONE)
600	    if (hp->rrp.peers->config && hp->rrp.config != *hp->rrp.peers->config) {
601	        pc->name = hp->rrp.peers->name;
602	        ngx_http_upstream_rr_peers_unlock(hp->rrp.peers);
603	        return NGX_BUSY;
604	    }
605	#endif
606	
607	    now = ngx_time();
608	    hcf = hp->conf;
609	
610	    points = hcf->points;
611	    point = &points->point[0];
612	
613	#if (NGX_HTTP_UPSTREAM_SID)
614	    best = ngx_http_upstream_get_rr_peer_by_sid(&hp->rrp, pc->hint, &best_i, 0);
615	
616	    if (best) {
617	        goto found;
618	    }
619	#endif
620	
621	    for ( ;; ) {
622	        server = point[hp->hash % points->number].server;
623	
624	        ngx_log_debug2(NGX_LOG_DEBUG_HTTP, pc->log, 0,
625	                       "consistent hash peer:%uD, server:\"%V\"",
626	                       hp->hash, server);
627	
628	        best = NULL;
629	        best_i = 0;
630	        total = 0;
631	
632	        for (peer = hp->rrp.peers->peer, i = 0;
633	             peer;
634	             peer = peer->next, i++)
635	        {
636	            n = i / (8 * sizeof(uintptr_t));
637	            m = (uintptr_t) 1 << i % (8 * sizeof(uintptr_t));
638	
639	            if (hp->rrp.tried[n] & m) {
640	                continue;
641	            }
642	
643	            if (peer->down) {
644	                continue;
645	            }
646	
647	            if (peer->max_fails
648	                && peer->fails >= peer->max_fails
649	                && now - peer->checked <= peer->fail_timeout)
650	            {
651	                continue;
652	            }
653	
654	            if (peer->max_conns && peer->conns >= peer->max_conns) {
655	                continue;
656	            }
657	
658	            if (peer->server.len != server->len
659	                || ngx_strncmp(peer->server.data, server->data, server->len)
660	                   != 0)
661	            {
662	                continue;
663	            }
664	
665	            peer->current_weight += peer->effective_weight;
666	            total += peer->effective_weight;
667	
668	            if (peer->effective_weight < peer->weight) {
669	                peer->effective_weight++;
670	            }
671	
672	            if (best == NULL || peer->current_weight > best->current_weight) {
673	                best = peer;
674	                best_i = i;
675	            }
676	        }
677	
678	        if (best) {
679	            best->current_weight -= total;
680	            goto found;
681	        }
682	
683	        hp->hash++;
684	        hp->tries++;
685	
686	        if (hp->tries > 20) {
687	            ngx_http_upstream_rr_peers_unlock(hp->rrp.peers);
688	            return hp->get_rr_peer(pc, &hp->rrp);
689	        }
690	    }
691	
692	found:
693	
694	    hp->rrp.current = best;
695	    ngx_http_upstream_rr_peer_ref(hp->rrp.peers, best);
696	
697	    pc->sockaddr = best->sockaddr;
698	    pc->socklen = best->socklen;
699	    pc->name = &best->name;
700	
701	#if (NGX_HTTP_UPSTREAM_SID)
702	    pc->sid = &best->sid;
703	#endif
704	
705	    best->conns++;
706	
707	    if (now - best->checked > best->fail_timeout) {
708	        best->checked = now;
709	    }
710	
711	    ngx_http_upstream_rr_peers_unlock(hp->rrp.peers);
712	
713	    n = best_i / (8 * sizeof(uintptr_t));
714	    m = (uintptr_t) 1 << best_i % (8 * sizeof(uintptr_t));
715	
716	    hp->rrp.tried[n] |= m;
717	
718	    return NGX_OK;
719	}
720	
721	
722	static void *
723	ngx_http_upstream_hash_create_conf(ngx_conf_t *cf)
724	{
725	    ngx_http_upstream_hash_srv_conf_t  *conf;
726	
727	    conf = ngx_palloc(cf->pool, sizeof(ngx_http_upstream_hash_srv_conf_t));
728	    if (conf == NULL) {
729	        return NULL;
730	    }
731	
732	    conf->points = NULL;
733	
734	    return conf;
735	}
