737	
738	static char *
739	ngx_http_upstream_hash(ngx_conf_t *cf, ngx_command_t *cmd, void *conf)
740	{
741	    ngx_http_upstream_hash_srv_conf_t  *hcf = conf;
742	
743	    ngx_str_t                         *value;
744	    ngx_http_upstream_srv_conf_t      *uscf;
745	    ngx_http_compile_complex_value_t   ccv;
746	
747	    value = cf->args->elts;
748	
749	    ngx_memzero(&ccv, sizeof(ngx_http_compile_complex_value_t));
750	
751	    ccv.cf = cf;
752	    ccv.value = &value[1];
753	    ccv.complex_value = &hcf->key;
754	
755	    if (ngx_http_compile_complex_value(&ccv) != NGX_OK) {
756	        return NGX_CONF_ERROR;
757	    }
758	
759	    uscf = ngx_http_conf_get_module_srv_conf(cf, ngx_http_upstream_module);
760	
761	    if (uscf->peer.init_upstream) {
762	        ngx_conf_log_error(NGX_LOG_WARN, cf, 0,
763	                           "load balancing method redefined");
764	    }
765	
766	    uscf->flags = NGX_HTTP_UPSTREAM_CREATE
767	                  |NGX_HTTP_UPSTREAM_MODIFY
768	                  |NGX_HTTP_UPSTREAM_WEIGHT
769	                  |NGX_HTTP_UPSTREAM_MAX_CONNS
770	                  |NGX_HTTP_UPSTREAM_MAX_FAILS
771	                  |NGX_HTTP_UPSTREAM_FAIL_TIMEOUT
772	                  |NGX_HTTP_UPSTREAM_DOWN;
773	
