216	ngx_http_upstream_get_random_peer(ngx_peer_connection_t *pc, void *data)
217	{
218	    ngx_http_upstream_random_peer_data_t  *rp = data;
219	
220	    time_t                             now;
221	    uintptr_t                          m;
222	    ngx_uint_t                         i, n;
223	    ngx_http_upstream_rr_peer_t       *peer;
224	    ngx_http_upstream_rr_peers_t      *peers;
225	    ngx_http_upstream_rr_peer_data_t  *rrp;
226	
227	    ngx_log_debug1(NGX_LOG_DEBUG_HTTP, pc->log, 0,
228	                   "get random peer, try: %ui", pc->tries);
229	
230	    rrp = &rp->rrp;
231	    peers = rrp->peers;
232	
233	    ngx_http_upstream_rr_peers_rlock(peers);
234	
235	    if (rp->tries > 20 || peers->number < 2) {
236	        ngx_http_upstream_rr_peers_unlock(peers);
237	        return ngx_http_upstream_get_round_robin_peer(pc, rrp);
238	    }
239	
240	#if (NGX_HTTP_UPSTREAM_ZONE)
241	    if (peers->config && rrp->config != *peers->config) {
242	        ngx_http_upstream_rr_peers_unlock(peers);
243	        return ngx_http_upstream_get_round_robin_peer(pc, rrp);
244	    }
245	#endif
246	
247	    pc->cached = 0;
248	    pc->connection = NULL;
249	
250	    now = ngx_time();
251	
252	#if (NGX_HTTP_UPSTREAM_SID)
253	    peer = ngx_http_upstream_get_rr_peer_by_sid(rrp, pc->hint, &i, 1);
254	
255	    if (peer) {
256	        n = i / (8 * sizeof(uintptr_t));
257	        m = (uintptr_t) 1 << i % (8 * sizeof(uintptr_t));
258	
259	        goto found;
260	    }
261	#endif
262	
263	    for ( ;; ) {
264	
265	        i = ngx_http_upstream_peek_random_peer(peers, rp);
266	
267	        peer = rp->conf->ranges[i].peer;
268	
269	        n = i / (8 * sizeof(uintptr_t));
270	        m = (uintptr_t) 1 << i % (8 * sizeof(uintptr_t));
271	
272	        if (rrp->tried[n] & m) {
273	            goto next;
274	        }
275	
276	        ngx_http_upstream_rr_peer_lock(peers, peer);
277	
278	        if (peer->down) {
279	            ngx_http_upstream_rr_peer_unlock(peers, peer);
280	            goto next;
281	        }
282	
283	        if (peer->max_fails
284	            && peer->fails >= peer->max_fails
285	            && now - peer->checked <= peer->fail_timeout)
286	        {
287	            ngx_http_upstream_rr_peer_unlock(peers, peer);
288	            goto next;
289	        }
290	
291	        if (peer->max_conns && peer->conns >= peer->max_conns) {
292	            ngx_http_upstream_rr_peer_unlock(peers, peer);
293	            goto next;
294	        }
295	
296	        break;
297	
298	    next:
299	
300	        if (++rp->tries > 20) {
301	            ngx_http_upstream_rr_peers_unlock(peers);
302	            return ngx_http_upstream_get_round_robin_peer(pc, rrp);
303	        }
304	    }
305	
306	#if (NGX_HTTP_UPSTREAM_SID)
307	found:
308	#endif
309	
310	    rrp->current = peer;
311	    ngx_http_upstream_rr_peer_ref(peers, peer);
312	
313	    if (now - peer->checked > peer->fail_timeout) {
314	        peer->checked = now;
315	    }
316	
317	    pc->sockaddr = peer->sockaddr;
318	    pc->socklen = peer->socklen;
319	    pc->name = &peer->name;
320	
321	#if (NGX_HTTP_UPSTREAM_SID)
322	    pc->sid = &peer->sid;
323	#endif
324	
325	    peer->conns++;
326	
327	    ngx_http_upstream_rr_peer_unlock(peers, peer);
328	    ngx_http_upstream_rr_peers_unlock(peers);
329	
330	    rrp->tried[n] |= m;
331	
332	    return NGX_OK;
333	}
