472	static ngx_uint_t
473	ngx_http_upstream_peek_random_peer(ngx_http_upstream_rr_peers_t *peers,
474	    ngx_http_upstream_random_peer_data_t *rp)
475	{
476	    ngx_uint_t  i, j, k, x;
477	
478	    x = ngx_random() % peers->total_weight;
479	
480	    i = 0;
481	    j = peers->number;
482	
483	    while (j - i > 1) {
484	        k = (i + j) / 2;
485	
486	        if (x < rp->conf->ranges[k].range) {
487	            j = k;
488	
489	        } else {
490	            i = k;
491	        }
492	    }
493	
494	    return i;
495	}
