288	
289	        *peerp = peer;
290	        (*peers->config)++;
291	    }
292	
293	    if (opeers) {
294	
295	        if (ngx_http_upstream_zone_preresolve(peers->resolve, peers,
296	                                              opeers->resolve, opeers)
297	            != NGX_OK)
298	        {
299	            return NULL;
300	        }
301	    }
302	
303	    if (peers->next == NULL) {
304	        goto done;
305	    }
306	
307	    backup = ngx_slab_alloc(shpool, sizeof(ngx_http_upstream_rr_peers_t));
308	    if (backup == NULL) {
309	        return NULL;
310	    }
311	
312	    ngx_memcpy(backup, peers->next, sizeof(ngx_http_upstream_rr_peers_t));
313	
314	    backup->name = name;
315	
316	    backup->shpool = shpool;
317	    backup->config = config;
318	
319	    for (peerp = &backup->peer; *peerp; peerp = &peer->next) {
320	        /* pool is unlocked */
321	        peer = ngx_http_upstream_zone_copy_peer(backup, *peerp);
322	        if (peer == NULL) {
323	            return NULL;
324	        }
325	
326	        *peerp = peer;
327	        (*backup->config)++;
328	    }
329	
330	    for (peerp = &backup->resolve; *peerp; peerp = &peer->next) {
331	        peer = ngx_http_upstream_zone_copy_peer(backup, *peerp);
332	        if (peer == NULL) {
333	            return NULL;
334	        }
335	
336	        *peerp = peer;
337	        (*backup->config)++;
338	    }
339	
340	    peers->next = backup;
341	
342	    if (opeers && opeers->next) {
343	
344	        if (ngx_http_upstream_zone_preresolve(peers->resolve, backup,
345	                                              opeers->resolve, opeers->next)
346	            != NGX_OK)
347	        {
348	            return NULL;
349	        }
350	
351	        if (ngx_http_upstream_zone_preresolve(backup->resolve, backup,
352	                                              opeers->next->resolve,
353	                                              opeers->next)
354	            != NGX_OK)
355	        {
356	            return NULL;
357	        }
358	    }
359	
360	done:
361	
362	    uscf->peer.data = peers;
363	
364	    ngx_http_upstream_zone_set_single(uscf);
365	
366	    return peers;
367	}
