369	
370	static ngx_http_upstream_rr_peer_t *
371	ngx_http_upstream_zone_copy_peer(ngx_http_upstream_rr_peers_t *peers,
372	    ngx_http_upstream_rr_peer_t *src)
373	{
374	    ngx_slab_pool_t              *pool;
375	    ngx_http_upstream_rr_peer_t  *dst;
376	
377	    pool = peers->shpool;
378	
379	    dst = ngx_slab_calloc_locked(pool, sizeof(ngx_http_upstream_rr_peer_t));
380	    if (dst == NULL) {
381	        return NULL;
382	    }
383	
384	    if (src) {
385	        ngx_memcpy(dst, src, sizeof(ngx_http_upstream_rr_peer_t));
386	        dst->sockaddr = NULL;
387	        dst->name.data = NULL;
388	#if (NGX_HTTP_UPSTREAM_SID)
389	        dst->sid.data = NULL;
390	#endif
391	        dst->server.data = NULL;
392	        dst->host = NULL;
393	    }
394	
395	    dst->sockaddr = ngx_slab_calloc_locked(pool, sizeof(ngx_sockaddr_t));
396	    if (dst->sockaddr == NULL) {
397	        goto failed;
398	    }
399	
400	    dst->name.data = ngx_slab_calloc_locked(pool, NGX_SOCKADDR_STRLEN);
401	    if (dst->name.data == NULL) {
402	        goto failed;
403	    }
404	
405	#if (NGX_HTTP_UPSTREAM_SID)
406	    dst->sid.data = ngx_slab_calloc_locked(pool, NGX_HTTP_UPSTREAM_SID_LEN);
407	    if (dst->sid.data == NULL) {
408	        goto failed;
409	    }
410	#endif
411	
412	    if (src) {
413	        ngx_memcpy(dst->sockaddr, src->sockaddr, src->socklen);
414	        ngx_memcpy(dst->name.data, src->name.data, src->name.len);
415	#if (NGX_HTTP_UPSTREAM_SID)
416	        ngx_memcpy(dst->sid.data, src->sid.data, src->sid.len);
417	#endif
418	
419	        dst->server.data = ngx_slab_alloc_locked(pool, src->server.len);
420	        if (dst->server.data == NULL) {
421	            goto failed;
422	        }
423	
424	        ngx_memcpy(dst->server.data, src->server.data, src->server.len);
425	
426	        if (src->host) {
427	            dst->host = ngx_slab_calloc_locked(pool,
428	                                             sizeof(ngx_http_upstream_host_t));
429	            if (dst->host == NULL) {
430	                goto failed;
431	            }
432	
433	            dst->host->name.data = ngx_slab_alloc_locked(pool,
434	                                                         src->host->name.len);
435	            if (dst->host->name.data == NULL) {
436	                goto failed;
437	            }
438	
439	            dst->host->peers = peers;
440	            dst->host->peer = dst;
441	
442	            dst->host->name.len = src->host->name.len;
443	            ngx_memcpy(dst->host->name.data, src->host->name.data,
444	                       src->host->name.len);
445	
446	            if (src->host->service.len) {
447	                dst->host->service.data = ngx_slab_alloc_locked(pool,
448	                                                        src->host->service.len);
449	                if (dst->host->service.data == NULL) {
450	                    goto failed;
451	                }
452	
453	                dst->host->service.len = src->host->service.len;
454	                ngx_memcpy(dst->host->service.data, src->host->service.data,
455	                           src->host->service.len);
456	            }
457	        }
458	    }
459	
460	    return dst;
461	
462	failed:
463	
464	    if (dst->host) {
465	        if (dst->host->name.data) {
466	            ngx_slab_free_locked(pool, dst->host->name.data);
467	        }
468	
469	        ngx_slab_free_locked(pool, dst->host);
470	    }
471	
472	    if (dst->server.data) {
473	        ngx_slab_free_locked(pool, dst->server.data);
474	    }
475	
476	#if (NGX_HTTP_UPSTREAM_SID)
477	    if (dst->sid.data) {
478	        ngx_slab_free_locked(pool, dst->sid.data);
479	    }
480	#endif
481	
482	    if (dst->name.data) {
483	        ngx_slab_free_locked(pool, dst->name.data);
484	    }
485	
486	    if (dst->sockaddr) {
487	        ngx_slab_free_locked(pool, dst->sockaddr);
488	    }
489	
490	    ngx_slab_free_locked(pool, dst);
491	
492	    return NULL;
493	}
