495	
496	static ngx_int_t
497	ngx_http_upstream_zone_preresolve(ngx_http_upstream_rr_peer_t *resolve,
498	    ngx_http_upstream_rr_peers_t *peers,
499	    ngx_http_upstream_rr_peer_t *oresolve,
500	    ngx_http_upstream_rr_peers_t *opeers)
501	{
502	    in_port_t                     port;
503	    ngx_str_t                    *server;
504	    ngx_http_upstream_host_t     *host;
505	    ngx_http_upstream_rr_peer_t  *peer, *template, *opeer, **peerp;
506	
507	    if (resolve == NULL || oresolve == NULL) {
508	        return NGX_OK;
509	    }
510	
511	    for (peerp = &peers->peer; *peerp; peerp = &(*peerp)->next) {
512	        /* void */
513	    }
514	
515	    ngx_http_upstream_rr_peers_rlock(opeers);
516	
517	    for (template = resolve; template; template = template->next) {
518	        for (opeer = oresolve; opeer; opeer = opeer->next) {
519	
520	            if (opeer->host->name.len != template->host->name.len
521	                || ngx_memcmp(opeer->host->name.data,
522	                              template->host->name.data,
523	                              template->host->name.len)
524	                   != 0)
525	            {
526	                continue;
527	            }
528	
529	            if (opeer->host->service.len != template->host->service.len
530	                || ngx_memcmp(opeer->host->service.data,
531	                              template->host->service.data,
532	                              template->host->service.len)
533	                   != 0)
534	            {
535	                continue;
536	            }
537	
538	            host = opeer->host;
539	
540	            for (opeer = opeers->peer; opeer; opeer = opeer->next) {
541	
542	                if (opeer->host != host) {
543	                    continue;
544	                }
545	
546	                peer = ngx_http_upstream_zone_copy_peer(peers, NULL);
547	                if (peer == NULL) {
548	                    ngx_http_upstream_rr_peers_unlock(opeers);
549	                    return NGX_ERROR;
550	                }
551	
552	                ngx_memcpy(peer->sockaddr, opeer->sockaddr, opeer->socklen);
553	
554	                if (template->host->service.len == 0) {
555	                    port = ngx_inet_get_port(template->sockaddr);
556	                    ngx_inet_set_port(peer->sockaddr, port);
557	                }
558	
559	                peer->socklen = opeer->socklen;
560	
561	                peer->name.len = ngx_sock_ntop(peer->sockaddr, peer->socklen,
562	                                               peer->name.data,
563	                                               NGX_SOCKADDR_STRLEN, 1);
564	
565	                peer->host = template->host;
566	
567	                template->host->valid = host->valid;
568	
569	                server = template->host->service.len ? &opeer->server
570	                                                     : &template->server;
571	
572	                peer->server.data = ngx_slab_alloc(peers->shpool, server->len);
573	                if (peer->server.data == NULL) {
574	                    ngx_http_upstream_rr_peers_unlock(opeers);
575	                    return NGX_ERROR;
576	                }
577	
578	                ngx_memcpy(peer->server.data, server->data, server->len);
579	                peer->server.len = server->len;
580	
581	                if (host->service.len == 0) {
582	                    peer->weight = template->weight;
583	
584	                } else {
585	                    peer->weight = (template->weight != 1 ? template->weight
586	                                                          : opeer->weight);
587	                }
588	
589	                peer->effective_weight = peer->weight;
590	                peer->max_conns = template->max_conns;
591	                peer->max_fails = template->max_fails;
592	                peer->fail_timeout = template->fail_timeout;
593	                peer->down = template->down;
594	
595	#if (NGX_HTTP_UPSTREAM_SID)
596	                ngx_http_upstream_copy_round_robin_sid(peer, template);
597	#endif
598	
599	                (*peers->config)++;
600	
601	                *peerp = peer;
602	                peerp = &peer->next;
603	
604	                peers->number++;
605	                peers->tries += (peer->down == 0);
606	                peers->total_weight += peer->weight;
607	                peers->weighted = (peers->total_weight != peers->number);
608	            }
609	
610	            break;
611	        }
612	    }
613	
614	    ngx_http_upstream_rr_peers_unlock(opeers);
615	    return NGX_OK;
616	}
