619	static void
620	ngx_http_upstream_zone_set_single(ngx_http_upstream_srv_conf_t *uscf)
621	{
622	    ngx_http_upstream_rr_peers_t  *peers;
623	
624	    peers = uscf->peer.data;
625	
626	    if (peers->number == 1
627	        && (peers->next == NULL || peers->next->number == 0))
628	    {
629	        peers->single = 1;
630	
631	    } else {
632	        peers->single = 0;
633	    }
634	}
