637	static void
638	ngx_http_upstream_zone_remove_peer_locked(ngx_http_upstream_rr_peers_t *peers,
639	    ngx_http_upstream_rr_peer_t *peer)
640	{
641	    peers->total_weight -= peer->weight;
642	    peers->number--;
643	    peers->tries -= (peer->down == 0);
644	    (*peers->config)++;
645	    peers->weighted = (peers->total_weight != peers->number);
646	
647	    ngx_http_upstream_rr_peer_free(peers, peer);
648	}
