651	static ngx_int_t
652	ngx_http_upstream_zone_init_worker(ngx_cycle_t *cycle)
653	{
654	    time_t                          now;
655	    ngx_msec_t                      timer;
656	    ngx_uint_t                      i;
657	    ngx_event_t                    *event;
658	    ngx_http_upstream_rr_peer_t    *peer;
659	    ngx_http_upstream_rr_peers_t   *peers;
660	    ngx_http_upstream_srv_conf_t   *uscf, **uscfp;
661	    ngx_http_upstream_main_conf_t  *umcf;
662	
663	    if (ngx_process != NGX_PROCESS_WORKER
664	        && ngx_process != NGX_PROCESS_SINGLE)
665	    {
666	        return NGX_OK;
667	    }
668	
669	    now = ngx_time();
670	    umcf = ngx_http_cycle_get_module_main_conf(cycle, ngx_http_upstream_module);
671	
672	    if (umcf == NULL) {
673	        return NGX_OK;
674	    }
675	
676	    uscfp = umcf->upstreams.elts;
677	
678	    for (i = 0; i < umcf->upstreams.nelts; i++) {
679	
680	        uscf = uscfp[i];
681	
682	        if (uscf->shm_zone == NULL) {
683	            continue;
684	        }
685	
686	        peers = uscf->peer.data;
687	
688	        do {
689	            ngx_http_upstream_rr_peers_wlock(peers);
690	
691	            for (peer = peers->resolve; peer; peer = peer->next) {
692	
693	                if (peer->host->worker != ngx_worker) {
694	                    continue;
695	                }
696	
697	                event = &peer->host->event;
698	                ngx_memzero(event, sizeof(ngx_event_t));
699	
700	                event->data = uscf;
701	                event->handler = ngx_http_upstream_zone_resolve_timer;
702	                event->log = cycle->log;
703	                event->cancelable = 1;
704	
705	                timer = (peer->host->valid > now)
706	                        ? (ngx_msec_t) 1000 * (peer->host->valid - now) : 1;
707	
708	                ngx_add_timer(event, timer);
709	            }
710	
711	            ngx_http_upstream_rr_peers_unlock(peers);
712	
713	            peers = peers->next;
714	
715	        } while (peers);
716	    }
717	
718	    return NGX_OK;
719	}
