721	
722	static void
723	ngx_http_upstream_zone_resolve_timer(ngx_event_t *event)
724	{
725	    ngx_resolver_ctx_t            *ctx;
726	    ngx_http_upstream_host_t      *host;
727	    ngx_http_upstream_srv_conf_t  *uscf;
728	
729	    host = (ngx_http_upstream_host_t *) event;
730	    uscf = event->data;
731	
732	    ctx = ngx_resolve_start(uscf->resolver, NULL);
733	    if (ctx == NULL) {
734	        goto retry;
735	    }
736	
737	    if (ctx == NGX_NO_RESOLVER) {
738	        ngx_log_error(NGX_LOG_ERR, event->log, 0,
739	                      "no resolver defined to resolve %V", &host->name);
740	        return;
741	    }
742	
743	    ctx->name = host->name;
744	    ctx->handler = ngx_http_upstream_zone_resolve_handler;
745	    ctx->data = host;
746	    ctx->timeout = uscf->resolver_timeout;
747	    ctx->service = host->service;
748	    ctx->cancelable = 1;
749	
750	    if (ngx_resolve_name(ctx) == NGX_OK) {
751	        return;
752	    }
753	
754	retry:
755	
756	    ngx_add_timer(event, ngx_max(uscf->resolver_timeout, 1000));
757	}
758	
759	
760	#define ngx_http_upstream_zone_addr_marked(addr)                              \
761	    ((uintptr_t) (addr)->sockaddr & 1)
762	
763	#define ngx_http_upstream_zone_mark_addr(addr)                                \
764	    (addr)->sockaddr = (struct sockaddr *) ((uintptr_t) (addr)->sockaddr | 1)
765	
766	#define ngx_http_upstream_zone_unmark_addr(addr)                              \
767	    (addr)->sockaddr =                                                        \
768	        (struct sockaddr *) ((uintptr_t) (addr)->sockaddr & ~((uintptr_t) 1))
769	
770	static void
771	ngx_http_upstream_zone_resolve_handler(ngx_resolver_ctx_t *ctx)
772	{
773	    time_t                         now;
774	    u_short                        min_priority;
775	    in_port_t                      port;
776	    ngx_str_t                     *server;
777	    ngx_msec_t                     timer;
778	    ngx_uint_t                     i, j, backup, addr_backup;
779	    ngx_event_t                   *event;
780	    ngx_resolver_addr_t           *addr;
781	    ngx_resolver_srv_name_t       *srv;
782	    ngx_http_upstream_host_t      *host;
783	    ngx_http_upstream_rr_peer_t   *peer, *template, **peerp;
784	    ngx_http_upstream_rr_peers_t  *peers;
785	    ngx_http_upstream_srv_conf_t  *uscf;
786	
787	    host = ctx->data;
788	    event = &host->event;
789	    uscf = event->data;
790	    peers = host->peers;
791	    template = host->peer;
792	
793	    ngx_http_upstream_rr_peers_wlock(peers);
794	
795	    now = ngx_time();
796	
797	    for (i = 0; i < ctx->nsrvs; i++) {
798	        srv = &ctx->srvs[i];
799	
800	        if (srv->state) {
801	            ngx_log_error(NGX_LOG_ERR, event->log, 0,
802	                          "%V could not be resolved (%i: %s) "
803	                          "while resolving service %V of %V",
804	                          &srv->name, srv->state,
805	                          ngx_resolver_strerror(srv->state), &ctx->service,
806	                          &ctx->name);
807	        }
808	    }
809	
810	    if (ctx->state) {
811	        if (ctx->service.len) {
812	            ngx_log_error(NGX_LOG_ERR, event->log, 0,
813	                          "service %V of %V could not be resolved (%i: %s)",
814	                          &ctx->service, &ctx->name, ctx->state,
815	                          ngx_resolver_strerror(ctx->state));
816	
817	        } else {
818	            ngx_log_error(NGX_LOG_ERR, event->log, 0,
819	                          "%V could not be resolved (%i: %s)",
820	                          &ctx->name, ctx->state,
821	                          ngx_resolver_strerror(ctx->state));
822	        }
823	
824	        if (ctx->state != NGX_RESOLVE_NXDOMAIN) {
825	            ngx_http_upstream_rr_peers_unlock(peers);
826	
827	            ngx_resolve_name_done(ctx);
828	
829	            ngx_add_timer(event, ngx_max(uscf->resolver_timeout, 1000));
830	            return;
831	        }
832	
833	        /* NGX_RESOLVE_NXDOMAIN */
834	
835	        ctx->naddrs = 0;
836	    }
837	
838	    backup = 0;
839	    min_priority = 65535;
840	
841	    for (i = 0; i < ctx->naddrs; i++) {
842	        min_priority = ngx_min(ctx->addrs[i].priority, min_priority);
843	    }
844	
845	#if (NGX_DEBUG)
846	    {
847	    u_char  text[NGX_SOCKADDR_STRLEN];
848	    size_t  len;
849	
850	    for (i = 0; i < ctx->naddrs; i++) {
851	        len = ngx_sock_ntop(ctx->addrs[i].sockaddr, ctx->addrs[i].socklen,
852	                            text, NGX_SOCKADDR_STRLEN, 1);
853	
854	        ngx_log_debug7(NGX_LOG_DEBUG_HTTP, event->log, 0,
855	                       "name %V was resolved to %*s "
856	                       "s:\"%V\" n:\"%V\" w:%d %s",
857	                       &host->name, len, text, &host->service,
858	                       &ctx->addrs[i].name, ctx->addrs[i].weight,
859	                       ctx->addrs[i].priority != min_priority ? "backup" : "");
860	    }
861	    }
862	#endif
863	
864	again:
865	
866	    for (peerp = &peers->peer; *peerp; /* void */ ) {
867	        peer = *peerp;
868	
869	        if (peer->host != host) {
870	            goto next;
871	        }
872	
873	        for (j = 0; j < ctx->naddrs; j++) {
874	
875	            addr = &ctx->addrs[j];
876	
877	            addr_backup = (addr->priority != min_priority);
878	            if (addr_backup != backup) {
879	                continue;
880	            }
881	
882	            if (ngx_http_upstream_zone_addr_marked(addr)) {
883	                continue;
884	            }
885	
886	            if (ngx_cmp_sockaddr(peer->sockaddr, peer->socklen,
887	                                 addr->sockaddr, addr->socklen,
888	                                 host->service.len != 0)
889	                != NGX_OK)
890	            {
891	                continue;
892	            }
893	
894	            if (host->service.len) {
895	                if (addr->name.len != peer->server.len
896	                    || ngx_strncmp(addr->name.data, peer->server.data,
897	                                   addr->name.len))
898	                {
899	                    continue;
900	                }
901	
902	                if (template->weight == 1 && addr->weight != peer->weight) {
903	                    continue;
904	                }
905	            }
906	
907	            ngx_http_upstream_zone_mark_addr(addr);
908	
909	            goto next;
910	        }
911	
912	        *peerp = peer->next;
913	        ngx_http_upstream_zone_remove_peer_locked(peers, peer);
914	
915	        ngx_http_upstream_zone_set_single(uscf);
916	
917	        continue;
918	
919	    next:
920	
921	        peerp = &peer->next;
922	    }
923	
924	    for (i = 0; i < ctx->naddrs; i++) {
925	
926	        addr = &ctx->addrs[i];
927	
928	        addr_backup = (addr->priority != min_priority);
929	        if (addr_backup != backup) {
930	            continue;
931	        }
932	
933	        if (ngx_http_upstream_zone_addr_marked(addr)) {
934	            ngx_http_upstream_zone_unmark_addr(addr);
935	            continue;
936	        }
937	
938	        ngx_shmtx_lock(&peers->shpool->mutex);
939	        peer = ngx_http_upstream_zone_copy_peer(peers, NULL);
940	        ngx_shmtx_unlock(&peers->shpool->mutex);
941	
942	        if (peer == NULL) {
943	            ngx_log_error(NGX_LOG_ERR, event->log, 0,
944	                          "cannot add new server to upstream \"%V\", "
945	                          "memory exhausted", peers->name);
946	            goto done;
947	        }
948	
949	        ngx_memcpy(peer->sockaddr, addr->sockaddr, addr->socklen);
950	
951	        if (host->service.len == 0) {
952	            port = ngx_inet_get_port(template->sockaddr);
953	            ngx_inet_set_port(peer->sockaddr, port);
954	        }
955	
956	        peer->socklen = addr->socklen;
957	
958	        peer->name.len = ngx_sock_ntop(peer->sockaddr, peer->socklen,
959	                                       peer->name.data, NGX_SOCKADDR_STRLEN, 1);
960	
961	        peer->host = template->host;
962	
963	        server = host->service.len ? &addr->name : &template->server;
964	
965	        peer->server.data = ngx_slab_alloc(peers->shpool, server->len);
966	        if (peer->server.data == NULL) {
967	            ngx_http_upstream_rr_peer_free(peers, peer);
968	
969	            ngx_log_error(NGX_LOG_ERR, event->log, 0,
970	                          "cannot add new server to upstream \"%V\", "
971	                          "memory exhausted", peers->name);
972	            goto done;
973	        }
974	
975	        peer->server.len = server->len;
976	        ngx_memcpy(peer->server.data, server->data, server->len);
977	
978	        if (host->service.len == 0) {
