987	        peer->max_conns = template->max_conns;
988	        peer->max_fails = template->max_fails;
989	        peer->fail_timeout = template->fail_timeout;
990	        peer->down = template->down;
991	
992	#if (NGX_HTTP_UPSTREAM_SID)
993	        ngx_http_upstream_copy_round_robin_sid(peer, template);
994	#endif
