996	        *peerp = peer;
997	        peerp = &peer->next;
998	
999	        peers->number++;
1000	        peers->tries += (peer->down == 0);
1001	        peers->total_weight += peer->weight;
1002	        peers->weighted = (peers->total_weight != peers->number);
1003	        (*peers->config)++;
1004	
